import numpy as np

def apply_tint(image, color):
    image_np = np.asarray(image).copy()
    red, green, blue = color

    for i in range(image.height):
        for j in range(image.width):
            r, g, b = image.getpixel((j, i))

            new_r, new_g, new_b = r + red, g + green, b + blue

            if new_r > 255:
                new_r = 255
            elif new_r < 0:
                new_r = 0

            if new_g > 255:
                new_g = 255
            elif new_g < 0:
                new_g = 0

            if new_b > 255:
                new_b = 255
            elif new_b < 0:
                new_b = 0

            image_np[i, j] = [new_r, new_g, new_b]

    return Image.fromarray(image_np)

