def add_files_to_tree(path):
    if os.path.isdir(path):
        leo_tree['children'][os.path.basename(path)] = {'files': [],
                    'children': {}}
    for f in os.listdir(path):
        new_path = os.path.join(path, f)
        if os.path.isfile(new_path):
            leo_tree['children'][os.path.basename(path)]['files'].append(f)
        elif os.path.isdir(new_path):
            add_files_to_tree(new_path)

